// 一键启动开关 (首页/设置页复用)
- (void)enableOneclickExclusivelyForVapp:(WBVAppModel *)targetVapp {
    for (WBVAppModel *item in WBVAppManager.sharedManager.myApps) {
        item.featureStatusInfo.isOneClickSwitchOn = (item.vid == targetVapp.vid);
    }
    [WBVAppManager.sharedManager saveOneClickStartStatusForVApp:targetVapp];
}

