+ (UIViewController *)getUIApplicationCurrentViewController {
    UIViewController *currentVC = [WBAppManager getUIApplicationRootViewController];

    BOOL runLoopFind = YES;
    while (runLoopFind && currentVC) {
        if (currentVC.presentedViewController) {
            currentVC = currentVC.presentedViewController;
        }
        else if ([currentVC isKindOfClass:[UINavigationController class]]) {
            currentVC = ((UINavigationController *)currentVC).visibleViewController;
        } else if ([currentVC isKindOfClass:[UITabBarController class]]) {
            currentVC = ((UITabBarController *)currentVC).selectedViewController;
        }
        else {
            runLoopFind = NO;
        }
    }
    return currentVC;
}

+ (void)setUIApplicationRootViewController:(UIViewController*)rootVC {
    [self setRootVC2Window:rootVC];
    NSMutableDictionary *data = [NSMutableDictionary dictionary];
    WBVAppModel *foundApp = [WBVAppManager.sharedManager.myApps filteredArrayUsingPredicate:
                                 [NSPredicate predicateWithFormat:@"featureStatusInfo.isOneClickSwitchOn == YES"]
    ].firstObject;
    if ([[WBBenefitManager sharedManager] isBenefitAvailable:WBUserBenefitOneClick] && foundApp && WBSettingManager.sharedManager.oneClickStart) {
        [WBAppManager sharedManager].entryMethod = WBAppEntryMethodOneclick;
    }
    data[@"entryMethod"] = @([WBAppManager sharedManager].entryMethod);
    if ([rootVC isKindOfClass:[WBSubMainViewController class]]) {
        data[@"isPretending"] = @(1);
    }
    [[WBActionRequestManager sharedManager] requestReportEventWithType:WBActionRequestEventTypeAppInitLaunch data:data defaultHandler:nil];
}

+ (void)setRootVC2Window:(UIViewController *)rootVC {
    UIWindow *window = [UIApplication sharedApplication].keyWindow;
    window.rootViewController = rootVC;
    [[WBPlugManager sharedManager] appDidSetRootViewController:rootVC];
}

