    [WBVAppDownloadManager.sharedManager onAppWillTerminate];// 通知虚拟应用下载管理器应用程序即将终止，可能涉及下载任务的保存或取消。
    [WBVAppResDownloadManager.sharedManager onAppWillTerminate];// 通知虚拟应用资源下载管理器应用程序即将终止，可能涉及资源下载任务的保存或取消。
}
