// 点击vapp消息调用的是这个方法
- (void)userNotificationCenter:(UNUserNotificationCenter *)center didReceiveNotificationResponse:(UNNotificationResponse *)response withCompletionHandler:(void (^)(void))completionHandler {
    if ([response.actionIdentifier containsString:@"UNNotificationDismissActionIdentifier"]) return;
    WBBaseActionModel *action = [self buildActionWithNotification:response.notification];
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];
    NSString *vappBundleId = response.notification.request.content.userInfo[@"vappBundleId"];
    if (vappBundleId) {
        [WBAppManager sharedManager].entryMethod = WBAppEntryMethodVappPushNotification;
    }
    if ([rootVC isKindOfClass:[WBMainViewController class]] || [rootVC isKindOfClass:[WBSubMainViewController class]]) {  // 前台、后台存活（支持伪装根视图）
        if(vappBundleId){
            [WBGroMoreAdManager sharedManager].vappMsgTapInAdClose = TRUE;
            [WBHomeViewController msgTappedCheckAndLaunchVApp:vappBundleId];
        }
        [action executeWithDefaultHandler:nil];
    } else { // Token hasn't yet been requested or is not on B page.    // 后台被杀，点击通知启动
        if(vappBundleId) {
            [WBGroMoreAdManager sharedManager].vappMsgTapInAdClose = TRUE;
            [WBAppManager sharedManager].vappBundleId = vappBundleId;
        } 
        [WBAppManager sharedManager].stashedAction = action;
    }
}

- (WBBaseActionModel *)buildActionWithNotification:(UNNotification *)notification {
    NSDictionary *apsDict = notification.request.content.userInfo;
    WBBaseActionModel *action = [[WBDefaultActionFactory sharedFactory] buildActionWithDict:apsDict sourceInterface:nil];
    return action;
}

